// Extract JSON from AI output - strict parsing
const output = $input.first().json.output;
let shorts = null;
let parseError = null;

if (typeof output === 'string') {
  try {
    // Try to extract JSON from markdown code block (```json...```)
    const jsonMatch = output.match(/```json\n([\s\S]*?)\n```/);
    if (jsonMatch && jsonMatch[1]) {
      shorts = JSON.parse(jsonMatch[1]);
    } else {
      // Fallback: try direct parsing
      shorts = JSON.parse(output);
    }
  } catch (e) {
    parseError = e.message;
    console.log('Parse error:', parseError);
    console.log('Output received:', output);
  }
} else if (output && typeof output === 'object') {
  shorts = output;
}

if (!shorts) {
  throw new Error(`Failed to parse AI output. Error: ${parseError}. Output: ${typeof output === 'string' ? output.substring(0, 200) : 'not a string'}`);
}

// Verify required fields
const required = ['bandName', 'bandInstagram', 'caption', 'postDate', 'hashtags', 'mentions'];
const missing = required.filter(f => !shorts[f]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}. Output: ${JSON.stringify(shorts)}`);
}

// Ensure all default fields exist
shorts.status = shorts.status || 'draft';
shorts.mediaLink = shorts.mediaLink || '';
shorts.platform = shorts.platform || 'YouTube';
shorts.suiteEStudios = shorts.suiteEStudios || 'Suite E Studios';
shorts.suiteEStudiosInstagram = shorts.suiteEStudiosInstagram || '@suite.e.studios';
shorts.eventType = shorts.eventType || 'Music';
shorts.mediaType = shorts.mediaType || 'Video';
shorts.postTime = shorts.postTime || '11:00 AM';

return { json: shorts };

// Convert JSON to markdown with YAML frontmatter + inline fields for Dataview
const j = $input.all()[0].json;

// Format mentions for frontmatter (array to string)
const mentionsStr = Array.isArray(j.mentions) ? j.mentions.join(', ') : j.mentions || '';

// Get current date
const today = new Date();
const createdDate = today.toISOString().split('T')[0];
const displayDate = today.toLocaleDateString();

// Build YAML frontmatter - Dataview optimized
const yaml = `---
title: "YouTube Short - ${j.bandNameString}"
type: youtube-short
status: ${j.status}
bandName: "${j.bandName}"
bandInstagram: "${j.bandInstagram}"
suiteEStudios: "${j.suiteEStudios}"
suiteEStudiosInstagram: "${j.suiteEStudiosInstagram}"
caption: "${j.caption.replace(/"/g, '\\"')}"
platform: "${j.platform}"
postDate: "${j.postDate}"
postTime: "${j.postTime}"
hashtags: "${j.hashtags}"
mentions: "${mentionsStr}"
eventType: "${j.eventType}"
mediaType: "${j.mediaType}"
ytPlaylist: "${j.ytPlaylist}"
ytTags: "${j.ytTags}"
mediaLink: "${j.mediaLink}"
bandNameString: "${j.bandNameString}"
bandUsernameIG: "${j.bandUsernameIG}"
created-date: ${createdDate}
---

# YouTube Short: ${j.bandNameString}

**Created:** ${displayDate}
**Date Posted:** ${j.postDate}
**Status:** ${j.status}

---

## 📌 Video Metadata (Dataview Queryable)

bandName:: ${j.bandName}
bandInstagram:: ${j.bandInstagram}
suiteEStudios:: ${j.suiteEStudios}
suiteEStudiosInstagram:: ${j.suiteEStudiosInstagram}
platform:: YouTube
status:: ${j.status}
postDate:: ${j.postDate}
postTime:: ${j.postTime}
eventType:: ${j.eventType}
mediaType:: ${j.mediaType}

---

## 📝 Caption

${j.caption}

---

## 🔗 Links & Media

mediaLink:: ${j.mediaLink ? '[View in Google Drive](' + j.mediaLink + ')' : 'Not yet added'}
ytPlaylist:: ${j.ytPlaylist || 'Not set'}
ytTags:: ${j.ytTags || 'Not set'}

---

## 👥 Mentions

${j.mentions.map(m => '- ' + m).join('\n')}

---

## 🏷️ Hashtags

${j.hashtags}

---

## ✅ Status Guide

- **draft** — New, still editing caption or waiting for media link
- **ready** — Approved & Google Drive link added, ready for YouTube upload
- **processing** — n8n is uploading to YouTube Shorts
- **published** — Live on YouTube ✅
- **failed** — Upload failed, check error details

**Current Status:** ${j.status}

---

## 📋 Workflow Checklist

- [ ] Caption is finalized and correct
- [ ] Video uploaded to Google Drive (public/shareable link)
- [ ] mediaLink field populated with Google Drive URL
- [ ] Hashtags are relevant and complete
- [ ] Mentions are correct
- [ ] Status changed to "ready"
- [ ] n8n uploads video to YouTube Shorts
- [ ] Status auto-updates to "published"
- [ ] YouTube link appears in file
`;

// Generate filename: MM.dd.yyyy | Band Name @bandnameIG.md
const [year, month, day] = j.postDate.split('-');
const filename = `${month}.${day}.${year} | ${j.bandName} ${j.bandUsernameIG}.md`;

return {
  json: {
    ...j,
    markdownContent: yaml,
    filename: filename,
    filenameSafe: filename.replace(/[^\w\s@\-\.\|]/g, '').trim()
  }
};

